document.addEventListener('DOMContentLoaded',()=>{const form=document.getElementById('form-comentario');if(form){form.addEventListener('submit',async function(e){e.preventDefault();const formData=new FormData(form);try{const response=await axios.post('/comentar',formData);document.getElementById('lista_comentarios').innerHTML=response.data;document.querySelector('#lista_comentarios .comentario:first-child')?.classList.add('destacado');const listaComentarios=document.getElementById('lista_comentarios');listaComentarios.style.opacity=0;setTimeout(()=>{listaComentarios.innerHTML=response.data;listaComentarios.style.transition='opacity 0.5s ease-in';listaComentarios.style.opacity=1;},200);form.querySelector('#comentario_texto').value='';}catch(error){console.error('Error al enviar comentario:',error);alert('Ocurrió un error al enviar tu comentario');}});}});